#include<cstdio>
#include<cstdlib>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define int long long
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
typedef long long LL;
const int N=3e6+10;
struct FHQ{int l,r,siz;short k;LL ql,qr,Sz;}t[N];
int Rt[N],T1,T2,T3,T4,T5,T6,T7,T8,rt,cnt;
inline int Node(LL l,LL r)
{
	t[++cnt].k=rand();t[cnt].ql=l;t[cnt].qr=r;
	t[cnt].Sz=r-l+1;t[cnt].siz=1;return cnt;
}
inline void update(int k)
{
	t[k].siz=t[t[k].l].siz+t[t[k].r].siz+1;
	t[k].Sz=t[t[k].l].Sz+t[t[k].r].Sz+(t[k].qr-t[k].ql+1);
}
inline void split(int cur,int k,int &x,int &y)
{
	if(!cur){x=y=0;return;}
	if(t[t[cur].l].siz>=k){y=cur;split(t[cur].l,k,x,t[cur].l);update(cur);return;}
	x=cur;split(t[cur].r,k-t[t[cur].l].siz-1,t[cur].r,y);update(cur);
}
inline int merge(int x,int y)
{
	if(!x||!y)return x|y;
	if(t[x].k<t[y].k){t[x].r=merge(t[x].r,y);update(x);return x;}
	t[y].l=merge(x,t[y].l);update(y);return y;
}
inline int Slide(int cur,LL pos)
{
	if(pos==t[cur].ql){++t[cur].ql;--t[cur].Sz;return cur;}
	if(pos==t[cur].qr){--t[cur].qr;--t[cur].Sz;return cur;}
	int k=Node(pos+1,t[cur].qr);t[cur].qr=pos-1;
	t[cur].Sz=t[cur].qr-t[cur].ql+1;return merge(cur,k);
}
inline int Sz(int k){return t[k].qr-t[k].ql+1;}
inline int Loc(int cur,int k)
{	
	
	if(t[cur].l){if(t[t[cur].l].Sz>=k)return Loc(t[cur].l,k);k-=t[t[cur].l].Sz;}
//	printf("Loc :: %d %d\n",cur,k);
	int csz=t[cur].qr-t[cur].ql+1;if(csz>=k)return t[t[cur].l].siz+1;
	return t[t[cur].l].siz+1+Loc(t[cur].r,k-csz);
}
