signed main()
{
	srand(19260817);int n=read(),m=read(),Q=read();
	rep(1,n,i)
	{
//		printf("%d :: %lld %lld\n",i,1ll*(i-1)*m+1,1ll*i*m-1);
		Rt[i]=Node(1ll*(i-1)*m+1,1ll*i*m-1);
		rt=merge(rt,Node(1ll*i*m,1ll*i*m));
	}
	
//	debug();
	while(Q--)
	{
		int x=read(),y=read();
		if(y==m)
		{
			split(rt,x-1,T1,T2);split(T2,1,T2,T3);
			printf("%lld\n",t[T2].ql);rt=merge(merge(T1,T3),T2);
//			debug();
			continue;
		}
		int k=Loc(Rt[x],y);
		split(Rt[x],k-1,T1,T2);split(T2,1,T2,T3);
//		if(Q==114511)
//		{
//			printf("k::%d\n",k);
//			printf("T1 = %d\nT2 = %d\nT3 = %d\n",T1,T2,T3);
//			debug();
//		}
		LL dlt=y-t[T1].Sz,pos=t[T2].ql+dlt-1;
		split(rt,x-1,T4,T5);split(T5,1,T5,T6);
		if(t[T2].Sz==1){rt=merge(merge(T4,T6),T2);Rt[x]=merge(merge(T1,T3),T5);}
		else
		{
			int np=Node(pos,pos);T2=Slide(T2,pos);
			Rt[x]=merge(merge(merge(T1,T2),T3),T5);rt=merge(merge(T4,T6),np);
		}
		printf("%lld\n",pos);//debug();
	}
}
